# BAD: raw exception — model can't act on a Python traceback
def get_user_bad(user_id: str) -> dict:
    # If this raises, the exception propagates as-is — model gets a confusing error string
    user = fetch_from_db(user_id)   # may raise
    return user

# GOOD: structured error the model can reason about
def get_user_good(user_id: str) -> dict:
    if not user_id.startswith("usr_"):
        return {
            "error": "INVALID_ID",
            "message": f"User ID must start with 'usr_', got: {user_id!r}",
            "retryable": False
        }
    try:
        user = fetch_from_db(user_id)
        return {"id": user.id, "name": user.name, "email": user.email, "role": user.role}
    except NotFoundError:
        return {
            "error": "NOT_FOUND",
            "message": f"No user found with ID {user_id}",
            "retryable": False
        }
    except DatabaseTimeoutError:
        return {
            "error": "TIMEOUT",
            "message": "Database query timed out. Try again in a few seconds.",
            "retryable": True
        }
    except Exception as e:
        return {
            "error": "INTERNAL_ERROR",
            "message": "An unexpected error occurred. The team has been notified.",
            "retryable": False
        }

