import base64, json

LIST_ORDERS_TOOL = {
    "name": "list_orders",
    "description": (
        "List orders with optional filters. Returns up to 20 per page. "
        "If has_more is true, pass next_page_token to retrieve the next page."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "status":          {"type": "string", "enum": ["all", "open", "shipped", "delivered"]},
            "next_page_token": {"type": "string", "description": "Token from previous response to get the next page"}
        },
        "required": []
    }
}

def list_orders(status: str = "all", next_page_token: str | None = None) -> dict:
    # Decode pagination offset from the token
    if next_page_token:
        offset = int(base64.b64decode(next_page_token).decode())
    else:
        offset = 0

    PAGE_SIZE = 20
    all_orders = [{"id": f"ORD-{i:05d}", "status": "open"} for i in range(1, 67)]
    page = all_orders[offset: offset + PAGE_SIZE]
    next_offset = offset + PAGE_SIZE
    has_more = next_offset < len(all_orders)

    return {
        "orders":          page,
        "total":           len(all_orders),
        "has_more":        has_more,
        "next_page_token": base64.b64encode(str(next_offset).encode()).decode() if has_more else None
    }

import anthropic, json
from bs4 import BeautifulSoup

client = anthropic.Anthropic()

WEB_FETCH_TOOL = {
    "name": "fetch_webpage",
    "description": "Fetch the text content of a webpage. Returns extracted plain text (not HTML).",
    "input_schema": {
        "type": "object",
        "properties": {
            "url": {"type": "string", "description": "URL to fetch (https:// required)"},
            "max_chars": {
                "type": "integer",
                "description": "Maximum characters to return (default 3000, max 8000)"
            }
        },
        "required": ["url"]
    }
}

def fetch_webpage(url: str, max_chars: int = 3000) -> dict:
    import urllib.request
    try:
        with urllib.request.urlopen(url, timeout=10) as resp:
            html = resp.read().decode("utf-8", errors="replace")
    except Exception as e:
        return {"error": "FETCH_FAILED", "message": str(e)}

    # Strip HTML, trim to max_chars — the model doesn't need raw HTML
    soup = BeautifulSoup(html, "html.parser")
    text = soup.get_text(separator=" ", strip=True)
    text = " ".join(text.split())   # collapse whitespace

    if len(text) > max_chars:
        text = text[:max_chars] + "...[truncated]"

    return {"url": url, "text": text, "char_count": len(text)}
